// --- types.d.ts ---
// types.d.ts
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string; // 'C' | 'F'
  forecast: ForecastDay[];
}

export interface FormattedWeather {
  tempDisplay: string;
  humidityDisplay: string;
  windDisplay: string;
  unitSymbol: string;
}

export interface HookReturn {
  formatted: FormattedWeather;
  currentDate: string;
  forecastData: ForecastDay[];
}

export interface WeatherHeaderProps {
  city: string;
  date: string;
}

export interface CurrentWeatherProps {
  temp: string;
  condition: string;
  unit: string;
}

export interface WeatherDetailsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface ForecastItemProps {
  data: ForecastDay;
  unit: string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const WEATHER_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Cloudy': '☁️',
  'Partly Cloudy': '⛅',
  'Rain': '🌧️',
  'Snow': '❄️',
  'Thunderstorm': '⛈️',
  'Mist': '🌫️',
  'Clear': '☀️',
  'default': '❓',
};

export const DEFAULT_UNIT = 'C';

export const UNIT_CONFIG = {
  C: {
    tempSymbol: '°C',
    windSpeedUnit: 'km/h',
  },
  F: {
    tempSymbol: '°F',
    windSpeedUnit: 'mph',
  },
};


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';
import type { Props, HookReturn } from './types';

export function useComponent(props: Props): HookReturn {
  const { temperature, humidity, windSpeed, unit = 'C', forecast = [] } = props;

  const formatted = useMemo(() => {
    const unitSymbol = `°${unit}`;
    const tempDisplay = `${Math.round(temperature)}°`;
    const humidityDisplay = `${humidity}%`;
    const windDisplay = `${windSpeed} ${unit === 'F' ? 'mph' : 'km/h'}`;

    return {
      tempDisplay,
      humidityDisplay,
      windDisplay,
      unitSymbol,
    };
  }, [temperature, humidity, windSpeed, unit]);

  const currentDate = useMemo(() => {
    return new Intl.DateTimeFormat('en-US', {
      weekday: 'long',
      month: 'short',
      day: 'numeric',
    }).format(new Date());
  }, []);

  return {
    formatted,
    currentDate,
    forecastData: forecast,
  };
}


