// components/CurrentWeather.tsx
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from './types';

/**
 * Maps common weather conditions to an appropriate emoji icon.
 */
const getWeatherIndicator = (condition: string): string => {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('partly cloudy')) return '⛅';
  if (c.includes('cloudy') || c.includes('overcast')) return '☁️';
  if (c.includes('rain') || c.includes('showers') || c.includes('drizzle')) return '🌧️';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('snow') || c.includes('flurries')) return '❄️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  return '🌡️';
};

/**
 * CurrentWeather component displays the primary temperature and weather status.
 */
export default function CurrentWeather({ temp, condition, unit }: CurrentWeatherProps) {
  const emoji = getWeatherIndicator(condition);

  return (
    <Stack
      direction="vertical"
      align="center"
      gap={8}
      style={{ padding: 'var(--ggui-spacing-4, 16px)' }}
    >
      {/* Temperature Display */}
      <Stack direction="horizontal" align="start" gap={4}>
        <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
          {temp}
        </Heading>
        <Heading
          level={3}
          color="var(--ggui-color-onSurface, #18181b)"
          style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
        >
          °{unit}
        </Heading>
      </Stack>

      {/* Condition Display */}
      <Stack direction="horizontal" align="center" gap={8}>
        <Text size="3xl" as="span">
          {emoji}
        </Text>
        <Text
          variant="bodyLarge"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {condition}
        </Text>
      </Stack>
    </Stack>
  );
}

