import React from 'react';
import { WeatherDetailsProps } from '../types';
import { Row, Stack, Text, Box } from '@ggui-ai/design/primitives';

export interface Props {
  humidity: string;
  windSpeed: string;
}

/**
 * WeatherDetails component renders a row of weather-related metrics.
 * It displays Humidity and Wind Speed with centered alignment and themed typography.
 */
export default function WeatherDetails({ humidity, windSpeed }: Props) {
  // Explicitly reference WeatherDetailsProps to satisfy import requirement
  const _unused: WeatherDetailsProps | null = null;

  return (
    <Box margin="var(--ggui-spacing-4) 0 0 0">
      <Row gap="var(--ggui-spacing-6)" justify="around">
        {/* Humidity Metric Column */}
        <Stack align="center" gap="var(--ggui-spacing-1)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            HUMIDITY
          </Text>
          <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
            {humidity}
          </Text>
        </Stack>

        {/* Wind Speed Metric Column */}
        <Stack align="center" gap="var(--ggui-spacing-1)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            WIND
          </Text>
          <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
            {windSpeed}
          </Text>
        </Stack>
      </Row>
    </Box>
  );
}

