// components/ForecastStrip.tsx
import React from 'react';
import { Stack, Row, Box, Divider, Text } from '@ggui-ai/design/primitives';

export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  forecast: ForecastDay[];
  unit: string;
}

interface ForecastItemProps {
  data: ForecastDay;
  unit: string;
}

/**
 * ForecastItem displays weather information for a single day.
 * Internal component used by ForecastStrip.
 */
function ForecastItem({ data, unit }: ForecastItemProps) {
  return (
    <Stack align="center" gap="var(--ggui-spacing-1)">
      <Text 
        variant="caption" 
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {data.day}
      </Text>
      <Box>
        <Text variant="bodyLarge">
          {data.icon}
        </Text>
      </Box>
      <Row gap="var(--ggui-spacing-1)">
        <Text variant="bodySmall" weight="bold">
          {data.high}°{unit}
        </Text>
        <Text 
          variant="bodySmall" 
          color="var(--ggui-color-onSurfaceVariant)"
        >
          {data.low}°{unit}
        </Text>
      </Row>
    </Stack>
  );
}

/**
 * ForecastStrip renders a horizontal row of daily weather forecasts.
 */
export default function ForecastStrip({ forecast, unit }: Props) {
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <Row
      justify="between"
      align="center"
      gap="var(--ggui-spacing-4)"
      style={{
        width: '100%',
        overflowX: 'auto',
        paddingBottom: 'var(--ggui-spacing-2)',
        WebkitOverflowScrolling: 'touch',
      }}
    >
      {forecast.map((item, index) => (
        <React.Fragment key={`${item.day}-${index}`}>
          <ForecastItem data={item} unit={unit} />
          {index < forecast.length - 1 && (
            <Divider 
              orientation="vertical" 
              margin="var(--ggui-spacing-2)"
              color="var(--ggui-color-outlineVariant)"
            />
          )}
        </React.Fragment>
      ))}
    </Row>
  );
}


