// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Container, Card, Stack, Divider, Box } from '@ggui-ai/design/primitives';
import { WeatherHeader, CurrentWeather, WeatherDetails, ForecastStrip } from './components';
import { useWeather } from './hooks';
import type { Props } from './types';

export default function Weather(props: Props) {
  const { city, condition } = props;
  const { formatted, currentDate, forecastData } = useWeather(props);

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-4, 16px)">
      <Card
        padding={0}
        shadow="md"
        radius="xl"
      >
        <Box
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          padding="var(--ggui-spacing-6, 24px)"
          borderRadius="var(--ggui-shape-radius-xl, 16px)"
        >
          <Stack gap="var(--ggui-spacing-6, 24px)" align="stretch">
            <WeatherHeader city={city} date={currentDate} />

            <CurrentWeather
              temp={formatted.tempDisplay}
              condition={condition}
              unit={formatted.unitSymbol}
            />

            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

            <WeatherDetails
              humidity={formatted.humidityDisplay}
              windSpeed={formatted.windDisplay}
            />

            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

            <ForecastStrip
              forecast={forecastData}
              unit={formatted.unitSymbol}
            />
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}


