// components/ElementCell.tsx
import React from 'react';
import { Box, Text, Heading, Stack } from '@ggui-ai/design/primitives';
import { ElementCellProps } from '../types';

/**
 * Maps element categories to specific themed color tokens.
 * Helps visually segment the periodic table into its chemical families.
 */
const getCategoryColor = (category: string): string => {
  const categoryMap: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'alkaline-earth-metal': 'var(--ggui-color-primary-200, #bae6fd)',
    'transition-metal': 'var(--ggui-color-info-100, #cffafe)',
    'post-transition-metal': 'var(--ggui-color-success-100, #dcfce7)',
    'metalloid': 'var(--ggui-color-warning-100, #fef3c7)',
    'polyatomic-nonmetal': 'var(--ggui-color-error-100, #fee2e2)',
    'diatomic-nonmetal': 'var(--ggui-color-error-200, #fecaca)',
    'noble-gas': 'var(--ggui-color-secondary-200, #ede9fe)',
    'lanthanide': 'var(--ggui-color-info-200, #a5f3fc)',
    'actinide': 'var(--ggui-color-success-200, #bbf7d0)',
  };
  return categoryMap[category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

/**
 * ElementCell renders an individual tile for the periodic table.
 * Handles categorization color, selection focus, and search matching visuals.
 */
export default function ElementCell({ element, isSelected, isMatch, onClick }: ElementCellProps) {
  const categoryColor = getCategoryColor(element.category);

  return (
    <Box
      // @ts-ignore - Generic Box primitive spreads props to the underlying div
      onClick={() => onClick(element)}
      padding={4}
      background={categoryColor}
      borderRadius="var(--ggui-spacing-1, 4px)"
      style={{
        position: 'relative',
        height: '100%',
        aspectRatio: '1/1',
        cursor: 'pointer',
        // Fade out elements that don't match the current search query
        opacity: isMatch ? 1 : 0.2,
        transition: 'all 200ms ease-in-out',
        // Visual lift and priority for the selected element
        transform: isSelected ? 'scale(1.1)' : 'scale(1)',
        zIndex: isSelected ? 10 : 1,
        // Centering the symbol and name
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        // Dynamic border for selection state
        border: isSelected 
          ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
          : '1px solid var(--ggui-color-outline, #d4d4d8)',
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))' : 'none',
      }}
    >
      {/* Atomic Number: Positioned in the top-left corner */}
      <div style={{ position: 'absolute', top: '2px', left: '4px' }}>
        <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {element.atomicNumber}
        </Text>
      </div>

      {/* Element Symbol and Name: Centered in the cell */}
      <Stack gap={0} align="center">
        <Heading level={4}>{element.symbol}</Heading>
        <Text variant="caption" truncate>
          {element.name}
        </Text>
      </Stack>
    </Box>
  );
}

// --- components/Legend.tsx ---
// components/Legend.tsx
import React from 'react';
import { Box, Stack, Text, Spacer } from '@ggui-ai/design/primitives';
import { LegendProps } from './types';

/**
 * Maps element categories to specific design token colors.
 * Used for consistent coloring between the grid and the legend.
 */
function getCategoryColor(category: string): string {
  const c = category.toLowerCase();
  switch (c) {
    case 'diatomic nonmetal':
      return 'var(--ggui-color-primary-200, #bae6fd)';
    case 'noble gas':
      return 'var(--ggui-color-primary-400, #38bdf8)';
    case 'alkali metal':
      return 'var(--ggui-color-error, #dc2626)';
    case 'alkaline earth metal':
      return 'var(--ggui-color-warning, #d97706)';
    case 'metalloid':
      return 'var(--ggui-color-success, #16a34a)';
    case 'polyatomic nonmetal':
      return 'var(--ggui-color-primary-100, #e0f2fe)';
    case 'post-transition metal':
      return 'var(--ggui-color-info, #0284c7)';
    case 'transition metal':
      return 'var(--ggui-color-primary-600, #0284c7)';
    case 'lanthanide':
      return 'var(--ggui-color-secondary-300, #d8b4fe)';
    case 'actinide':
      return 'var(--ggui-color-secondary-600, #9333ea)';
    default:
      return 'var(--ggui-color-outline, #d4d4d8)';
  }
}

/**
 * Formats the category string for display (e.g., "noble gas" -> "Noble Gas").
 */
const formatCategoryName = (name: string): string => {
  return name
    .split(' ')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

export default function Legend({ categories }: LegendProps) {
  return (
    <Box
      padding="var(--ggui-spacing-4, 16px)"
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
    >
      <Stack gap="var(--ggui-spacing-2, 8px)">
        <Text
          variant="overline"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          ELEMENT CATEGORIES
        </Text>

        <Stack
          direction="horizontal"
          wrap={true}
          gap="var(--ggui-spacing-4, 16px)"
        >
          {categories.map((category) => (
            <Stack
              key={category}
              direction="horizontal"
              align="center"
              gap="var(--ggui-spacing-2, 8px)"
            >
              <Box
                background={getCategoryColor(category)}
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
              >
                <Spacer size={16} />
              </Box>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {formatCategoryName(category)}
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}


// --- components/DetailPanel.tsx ---
// components/DetailPanel.tsx
import React from 'react';
import {
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Badge,
  Button,
  Divider,
  Icon,
} from '@ggui-ai/design/primitives';
import { DetailPanelProps } from './types';

/**
 * Maps element categories to semantic color tokens.
 */
const getCategoryColor = (category: string) => {
  const cat = category.toLowerCase();
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('alkali')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-100, #cffafe)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-warning-100, #fef3c7)';
  return 'var(--ggui-color-surface, #fafafa)';
};

export default function DetailPanel({ element, onClose }: DetailPanelProps) {
  if (!element) return null;

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      shadow="md"
      radius="lg"
      style={{ 
        minHeight: '400px', 
        position: 'sticky', 
        top: 'var(--ggui-spacing-4, 16px)',
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)'
      }}
    >
      <Stack gap={16}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {element.name}
          </Heading>
          <Button variant="ghost" size="sm" onClick={onClose}>
            <Icon name="x" size={18} />
          </Button>
        </Stack>

        {/* Detail Content Hero */}
        <Stack direction="horizontal" gap={16} align="center">
          <Box
            padding={16}
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            background={getCategoryColor(element.category)}
            style={{
              width: '100px',
              height: '100px',
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              position: 'relative',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Text
              size="sm"
              weight="bold"
              style={{ position: 'absolute', top: 8, left: 8 }}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {element.atomicNumber}
            </Text>
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {element.symbol}
            </Text>
          </Box>
          <Stack gap={4}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Category
            </Text>
            <Badge variant="primary" size="lg">
              {element.category}
            </Badge>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* Metadata Grid */}
        <Stack gap={16}>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
            <Text variant="bodyLarge" weight="medium">{element.atomicWeight}</Text>
          </Stack>

          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
            <Text variant="bodyLarge" weight="medium">{element.atomicNumber}</Text>
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

