import React from 'react';
import { Container, Stack, Heading, Box, Divider } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';
import type { Props, HookReturn } from './types';
import { ElementCell, Legend, DetailPanel } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const { elements, searchQuery, setSearchQuery, selectedElement, setSelectedElement, filteredElements, allCategories } = props;

  return (
    <Box background="var(--ggui-color-surface, #fafafa)" paddingY="var(--ggui-spacing-8, 32px)">
      <Container maxWidth="xl">
        <Stack gap="var(--ggui-spacing-8, 32px)">
          <Stack 
            direction="horizontal" 
            justify="between" 
            align="center" 
            wrap 
            gap="var(--ggui-spacing-4, 16px)"
          >
            <Heading level={1}>Periodic Table of Elements</Heading>
            <Box style={{ width: '100%', maxWidth: '320px' }}>
              <SearchField
                value={searchQuery}
                onChange={setSearchQuery}
                placeholder="Search by name or symbol..."
              />
            </Box>
          </Stack>

          <Divider margin={0} />

          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1, 4px)',
              overflowX: 'auto',
              padding: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {elements.map((element) => {
              const isSelected = selectedElement?.symbol === element.symbol;
              const isMatch = filteredElements.some(fe => fe.symbol === element.symbol);

              return (
                <div 
                  key={element.symbol}
                  style={{ 
                    gridRow: element.row, 
                    gridColumn: element.col 
                  }}
                >
                  <ElementCell
                    element={element}
                    isSelected={isSelected}
                    isMatch={isMatch}
                    onClick={setSelectedElement}
                  />
                </div>
              );
            })}
          </Box>

          <Legend categories={allCategories} />

          {selectedElement && (
            <DetailPanel 
              element={selectedElement} 
              onClose={() => setSelectedElement(null)} 
            />
          )}
        </Stack>
      </Container>
    </Box>
  );
}


