/**
 * Maps weather condition names to emoji icons.
 */
export const CONDITION_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Cloudy': '☁️',
  'Rain': '🌧️',
  'Storm': '⛈️',
  'Snow': '❄️',
  'Partly Cloudy': '⛅',
  'Default': '🌡️',
};

/**
 * Maps temperature unit codes to their display symbols.
 */
export const UNIT_SYMBOLS = {
  'C': '°C',
  'F': '°F',
} as const;


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, UseWeatherReturn } from './types';

const CONDITION_ICONS: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  'partly cloudy': '⛅',
  clear: '☀️',
  thunderstorm: '⛈️',
  snow: '❄️',
  mist: '🌫️',
};

/**
 * Hook to transform raw weather data into formatted display strings.
 */
export function useWeather(props: WeatherCardProps): UseWeatherReturn {
  const { temperature, condition, humidity, windSpeed, unit = 'C' } = props;

  return useMemo(() => {
    const unitLabel = `°${unit}`;
    const formattedTemp = `${Math.round(temperature)}${unitLabel}`;
    const formattedHumidity = `${humidity}%`;
    const formattedWindSpeed = `${windSpeed} km/h`;

    const conditionKey = condition.toLowerCase();
    const conditionIcon = CONDITION_ICONS[conditionKey] || '🌡️';

    return {
      formattedTemp,
      formattedHumidity,
      formattedWindSpeed,
      unitLabel,
      conditionIcon,
    };
  }, [temperature, condition, humidity, windSpeed, unit]);
}


