import React from 'react';
import { Box, Stack, Heading, Text } from '@ggui-ai/design/primitives';
import type { WeatherMainProps } from './types';

/**
 * WeatherMain component displays the primary current weather information.
 * It includes an icon based on the condition, the temperature with unit,
 * and the descriptive weather condition text.
 */
export function WeatherMain({ temperature, condition, unit }: WeatherMainProps) {
  // Helper to map weather conditions to emojis for visual interest
  const getWeatherIcon = (weatherCondition: string) => {
    const c = weatherCondition.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '🌡️';
  };

  return (
    <div role="region" aria-label="Current Weather">
      <Box paddingY="var(--ggui-spacing-8)">
        <Stack align="center" gap="var(--ggui-spacing-4)">
          {/* Optional: Visual icon for the weather condition */}
          <Text size="4xl" aria-hidden="true">
            {getWeatherIcon(condition)}
          </Text>

          {/* Primary Temperature Display */}
          <Heading 
            level={1} 
            color="var(--ggui-color-onSurface)" 
            align="center"
          >
            {Math.round(temperature)}°{unit}
          </Heading>

          {/* Secondary Condition Text */}
          <Text 
            variant="bodyLarge" 
            color="var(--ggui-color-onSurfaceVariant)" 
            align="center"
          >
            {condition}
          </Text>
        </Stack>
      </Box>
    </div>
  );
}


