// --- types.d.ts ---
import React, { useState, useMemo } from 'react';
import {
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Card,
  Button,
  Divider,
  Badge
} from '@ggui-ai/design';

// --- Types ---

export interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  row: number;
  col: number;
}

export interface PeriodicTableProps {
  elements: Element[];
}

export interface HookReturn {
  filteredElements: Element[];
  selectedElement: Element | null;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  handleElementClick: (element: Element) => void;
  categories: string[];
}

export interface ElementCellProps {
  element: Element;
  isSelected: boolean;
  isHighlighted: boolean;
  onClick: (element: Element) => void;
  colorToken: string;
}

export interface TableGridProps {
  elements: Element[];
  filteredElements: Element[];
  selectedElement: Element | null;
  onElementClick: (element: Element) => void;
}

export interface LegendProps {
  categories: string[];
}

export interface DetailPanelProps {
  element: Element | null;
}

// --- Category Color Mapping ---

const categoryColors: Record<string, string> = {
  'reactive-nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'noble-gas': 'var(--ggui-color-secondary-100, #f4f4f5)',
  'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
  'post-transition-metal': 'var(--ggui-color-info-100, #e0f2fe)',
  'transition-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
  'lanthanide': 'var(--ggui-color-tertiary-100, #f5f3ff)',
  'actinide': 'var(--ggui-color-error-50, #fef2f2)',
  'unknown': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
};

// --- Hook ---

export const usePeriodicTable = (elements: Element[]): HookReturn => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerTerm = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerTerm) ||
        el.symbol.toLowerCase().includes(lowerTerm) ||
        el.atomicNumber.toString() === searchTerm
    );
  }, [elements, searchTerm]);

  const categories = useMemo(() => {
    return Array.from(new Set(elements.map((el) => el.category)));
  }, [elements]);

  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
  };

  return {
    filteredElements,
    selectedElement,
    searchTerm,
    setSearchTerm,
    handleElementClick,
    categories,
  };
};

// --- Components ---

export const ElementCell: React.FC<ElementCellProps> = ({
  element,
  isSelected,
  isHighlighted,
  onClick,
  colorToken,
}) => {
  return (
    <div
      onClick={() => onClick(element)}
      style={{
        gridRow: element.row,
        gridColumn: element.col,
        cursor: 'pointer',
        transition: 'all 0.2s ease-in-out',
        transform: isSelected ? 'scale(1.1)' : 'scale(1)',
        zIndex: isSelected ? 10 : 1,
      }}
    >
      <Box
        padding={8}
        background={colorToken}
        borderRadius={4}
        margin={2}
        style={{
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          border: isSelected
            ? '2px solid var(--ggui-color-primary-600, #0284c7)'
            : isHighlighted
            ? '2px solid var(--ggui-color-outline, #d4d4d8)'
            : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          opacity: isHighlighted || !isHighlighted ? 1 : 0.4, // Simplified highlight logic
          boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
        } as React.CSSProperties}
      >
        <Text variant="caption" size="xs" weight="bold">
          {element.atomicNumber}
        </Text>
        <Text variant="bodyLarge" weight="bold">
          {element.symbol}
        </Text>
        <Text variant="caption" truncate>
          {element.name}
        </Text>
      </Box>
    </div>
  );
};

export const TableGrid: React.FC<TableGridProps> = ({
  elements,
  filteredElements,
  selectedElement,
  onElementClick,
}) => {
  const filteredIds = new Set(filteredElements.map((el) => el.atomicNumber));

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-10, 40px), 1fr))',
        gridTemplateRows: 'repeat(7, minmax(var(--ggui-spacing-12, 48px), 1fr))',
        gap: 'var(--ggui-spacing-0-5, 2px)',
        overflowX: 'auto',
        padding: 'var(--ggui-spacing-4, 16px)',
        background: 'var(--ggui-color-surface, #ffffff)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      {elements.map((el) => (
        <ElementCell
          key={el.atomicNumber}
          element={el}
          isSelected={selectedElement?.atomicNumber === el.atomicNumber}
          isHighlighted={filteredIds.has(el.atomicNumber)}
          onClick={onElementClick}
          colorToken={categoryColors[el.category] || categoryColors['unknown']}
        />
      ))}
    </div>
  );
};

export const Legend: React.FC<LegendProps> = ({ categories }) => {
  return (
    <Stack direction="horizontal" wrap gap={12} justify="center">
      {categories.map((cat) => (
        <Stack key={cat} direction="horizontal" gap={4} align="center">
          <Box
            padding={6}
            background={categoryColors[cat] || categoryColors['unknown']}
            borderRadius={4}
          />
          <Text variant="caption">{cat.replace(/-/g, ' ')}</Text>
        </Stack>
      ))}
    </Stack>
  );
};

export const DetailPanel: React.FC<DetailPanelProps> = ({ element }) => {
  if (!element) {
    return (
      <Card padding={24} shadow="sm">
        <Stack align="center" justify="center" gap={12}>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Select an element to view details
          </Text>
        </Stack>
      </Card>
    );
  }

  return (
    <Card padding={24} shadow="md">
      <Stack gap={16}>
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={2}>
            <Heading level={2}>{element.name}</Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {element.category.replace(/-/g, ' ')}
            </Text>
          </Stack>
          <Box
            paddingX={16}
            paddingY={8}
            background={categoryColors[element.category]}
            borderRadius={8}
          >
            <Text variant="bodyLarge" weight="bold" size="2xl">
              {element.symbol}
            </Text>
          </Box>
        </Stack>

        <Divider />

        <Stack gap={8}>
          <Stack direction="horizontal" justify="between">
            <Text variant="label">Atomic Number</Text>
            <Text variant="body">{element.atomicNumber}</Text>
          </Stack>
          <Stack direction="horizontal" justify="between">
            <Text variant="label">Atomic Weight</Text>
            <Text variant="body">{element.atomicWeight} u</Text>
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
};

// --- Main Component ---

const PeriodicTable: React.FC<PeriodicTableProps> = ({ elements }) => {
  const {
    filteredElements,
    selectedElement,
    searchTerm,
    setSearchTerm,
    handleElementClick,
    categories,
  } = usePeriodicTable(elements);

  return (
    <Box padding={24}>
      <Stack gap={32}>
        <Stack gap={16} align="center">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Box style={{ width: '100%', maxWidth: '400px' }}>
            <Input label="Search Elements" placeholder="Search by name, symbol, or number..." value={searchTerm} onChange={setSearchTerm} />
          </Box>
        </Stack>
      </Stack>

      <Stack gap={24}>
        <TableGrid
          elements={elements}
          filteredElements={filteredElements}
          selectedElement={selectedElement}
          onElementClick={handleElementClick}
        />
        <Legend categories={categories} />
      </Stack>

      <Box style={{ maxWidth: '600px', margin: '0 auto', width: '100%' }}>
        <DetailPanel element={selectedElement} />
      </Box>
    </Box>
  );
};

