// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useMemo, useCallback } from 'react';
import type { PeriodicTableProps as Props, HookReturn, Element } from './types';

export function useComponent(props: Props): HookReturn {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm.trim()) {
      return props.elements;
    }
    const lowerSearch = searchTerm.toLowerCase();
    return props.elements.filter(
      (element) =>
        element.name.toLowerCase().includes(lowerSearch) ||
        element.symbol.toLowerCase().includes(lowerSearch)
    );
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => {
    const uniqueCategories = new Set(props.elements.map((el) => el.category));
    return Array.from(uniqueCategories);
  }, [props.elements]);

  const handleElementClick = useCallback(
    (element: Element) => {
      setSelectedElement((prev) => (prev?.atomicNumber === element.atomicNumber ? null : element));
    },
    [setSelectedElement]
  );

  return {
    filteredElements,
    selectedElement,
    searchTerm,
    setSearchTerm,
    handleElementClick,
    categories,
  };
}


