import React, { useState } from 'react';
import { Box, Stack, Text, Spacer } from '@ggui-ai/design/primitives';
import type { Element, ElementCellProps } from './types';

/**
 * ElementCell — A single cell in the Periodic Table representing a chemical element.
 * It uses the Box primitive for its container and Text/Stack/Spacer for internal layout.
 */
export function ElementCell({
  element,
  isSelected,
  isHighlighted,
  onClick,
  colorToken,
}: ElementCellProps) {
  // State for hover effect as per instructions
  const [isHovered, setIsHovered] = useState(false);

  const handleClick = () => {
    if (isHighlighted) {
      onClick(element);
    }
  };

  // Keyboard accessibility for role="button"
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (isHighlighted && (e.key === 'Enter' || e.key === ' ')) {
      e.preventDefault();
      onClick(element);
    }
  };

  // Container style for the grid item
  const containerStyle: React.CSSProperties = {
    gridRow: element.row,
    gridColumn: element.col,
    width: '100%',
    height: '100%',
    aspectRatio: '1/1',
    minWidth: '60px',
    minHeight: '60px',
  };

  // Style for the interactive element inside the Box
  const interactiveStyle: React.CSSProperties = {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    width: '100%',
    outline: 'none',
    opacity: isHighlighted ? 1 : 0.3,
    cursor: isHighlighted ? 'pointer' : 'default',
    padding: 'var(--ggui-spacing-1, 4px)',
    boxSizing: 'border-box',
    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
    border: isSelected
      ? '2px solid var(--ggui-color-primary-500)'
      : '1px solid var(--ggui-color-outline, #d4d4d8)',
    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
    boxShadow: isHovered && isHighlighted 
      ? 'var(--ggui-shape-shadow-md)' 
      : 'none',
    transform: isHovered && isHighlighted ? 'scale(1.02)' : 'scale(1)',
    zIndex: isHovered && isHighlighted ? 10 : isSelected ? 5 : 1,
  };

  return (
    <div style={containerStyle}>
      <Box
        background={colorToken}
        borderRadius={4}
        padding={0}
      >
        <div
          role="button"
          tabIndex={isHighlighted ? 0 : -1}
          onClick={handleClick}
          onKeyDown={handleKeyDown}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          aria-label={`${element.name} (${element.symbol})`}
          aria-pressed={isSelected}
          style={interactiveStyle}
        >
          <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
            {element.atomicNumber}
          </Text>

          <Spacer size="flex" />

          <Stack align="center" justify="center">
            <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {element.symbol}
            </Text>
          </Stack>

          <Spacer size="flex" />
        </div>
      </Box>
    </div>
  );
}


