import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';
import type { Element, TableGridProps } from './types';

/**
 * ElementCell renders an individual chemical element in the periodic table grid.
 * It shows the atomic number, symbol, and name.
 */
function ElementCell({
  element,
  isSelected,
  isHighlighted,
  onClick,
  colorToken,
}: {
  element: Element;
  isSelected: boolean;
  isHighlighted: boolean;
  onClick: (element: Element) => void;
  colorToken: string;
}) {
  return (
    <Box
      padding={4}
      borderRadius="var(--ggui-shape-radius-sm, 4px)"
      background={isHighlighted ? colorToken : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
      style={{
        gridRow: element.row,
        gridColumn: element.col,
        cursor: 'pointer',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
        border: isSelected
          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
          : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        opacity: isHighlighted ? 1 : 0.4,
        transform: isSelected ? 'scale(1.08)' : 'scale(1)',
        zIndex: isSelected ? 10 : 1,
        aspectRatio: '1 / 1',
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
      }}
      // @ts-ignore - Primitives usually forward standard event handlers
      onClick={() => onClick(element)}
    >
      <Text
        variant="caption"
        size="xs"
        style={{
          position: 'absolute',
          top: '2px',
          left: '4px',
          fontSize: '10px',
          color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
        }}
      >
        {element.atomicNumber}
      </Text>
      <Text weight="bold" size="lg" align="center" color="var(--ggui-color-onSurface, #18181b)">
        {element.symbol}
      </Text>
      <Text
        variant="caption"
        size="xs"
        truncate
        align="center"
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
        style={{ fontSize: '9px', marginTop: '-2px', width: '100%' }}
      >
        {element.name}
      </Text>
    </Box>
  );
}

/**
 * Maps element categories to semantic color tokens from the design system.
 */
const getCategoryColor = (category: string) => {
  const colors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition metal': 'var(--ggui-color-info-100, #cffafe)',
    'post-transition metal': 'var(--ggui-color-success-100, #dcfce7)',
    'metalloid': 'var(--ggui-color-info-200, #bae6fd)',
    'polyatomic nonmetal': 'var(--ggui-color-primary-50, #f0f9ff)',
    'diatomic nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
    'noble gas': 'var(--ggui-color-error-100, #fee2e2)',
    'lanthanide': 'var(--ggui-color-info-50, #ecfeff)',
    'actinide': 'var(--ggui-color-error-50, #fef2f2)',
  };
  return colors[category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

export function TableGrid({
  elements,
  filteredElements,
  selectedElement,
  onElementClick,
}: TableGridProps) {
  return (
    <Box
      padding={16}
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
      style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
        gap: 'var(--ggui-spacing-1, 4px)',
        overflowX: 'auto',
        minWidth: '1000px',
        background: 'var(--ggui-color-surface, #fafafa)',
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      {elements.map((element) => {
        const isSelected = element.atomicNumber === selectedElement?.atomicNumber;
        const isHighlighted = filteredElements.some(
          (e) => e.atomicNumber === element.atomicNumber
        );

        return (
          <ElementCell
            key={element.atomicNumber}
            element={element}
            isSelected={isSelected}
            isHighlighted={isHighlighted}
            onClick={onElementClick}
            colorToken={getCategoryColor(element.category)}
          />
        );
      })}
    </Box>
  );
}


