import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import type { LegendProps } from './types';

/**
 * Maps periodic table categories to theme-compliant color tokens.
 * Uses a variety of primary shades and semantic state colors for visual distinction.
 */
const getCategoryColor = (category: string): string => {
  const colorMap: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-error, #dc2626)',
    'alkaline-earth-metal': 'var(--ggui-color-warning, #d97706)',
    'transition-metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'post-transition-metal': 'var(--ggui-color-success, #16a34a)',
    'metalloid': 'var(--ggui-color-primary-300, #7dd3fc)',
    'nonmetal': 'var(--ggui-color-primary-900, #0c4a6e)',
    'halogen': 'var(--ggui-color-primary-700, #0369a1)',
    'noble-gas': 'var(--ggui-color-primary-600, #0284c7)',
    'lanthanide': 'var(--ggui-color-primary-200, #bae6fd)',
    'actinide': 'var(--ggui-color-primary-800, #075985)',
  };
  return colorMap[category] || 'var(--ggui-color-outline, #d4d4d8)';
};

/**
 * Formats kebab-case strings (e.g., 'alkali-metal') to Title Case ('Alkali Metal').
 */
const formatCategory = (category: string): string => {
  return category
    .split('-')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

/**
 * Legend component that displays the color-coding for element categories.
 */
export function Legend({ categories }: LegendProps) {
  return (
    <div
      aria-label="Element Categories Legend"
      style={{
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        overflow: 'hidden',
      }}
    >
      <Box
        padding="var(--ggui-spacing-4, 16px)"
        background="var(--ggui-color-surface, #fafafa)"
      >
        <Stack
          direction="horizontal"
          wrap={true}
          gap="var(--ggui-spacing-4, 16px)"
          align="center"
        >
          {categories.map((category) => (
            <Stack
              key={category}
              direction="horizontal"
              align="center"
              gap="var(--ggui-spacing-2, 8px)"
            >
              <Box
                padding={0}
                borderRadius="var(--ggui-spacing-1, 4px)"
                background={getCategoryColor(category)}
                style={{
                  width: '16px',
                  height: '16px',
                  flexShrink: 0,
                }}
              />
              <Text
                variant="caption"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {formatCategory(category)}
              </Text>
            </Stack>
          ))}
        </Stack>
      </Box>
    </div>
  );
}


// --- components/DetailPanel.tsx ---
import React from 'react';
import { Card, Stack, Row, Box, Text, Heading, Divider, Badge } from '@ggui-ai/design/primitives';
import { DetailPanelProps } from './types';

export function DetailPanel({ element }: DetailPanelProps) {
  // Empty State: If element is null, prompt selection
  if (!element) {
    return (
      <Card padding="var(--ggui-spacing-12)" shadow="sm" border>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
          Select an element to view details.
        </Text>
      </Card>
    );
  }

  // Main Layout: Detailed view of the selected element
  return (
    <Card 
      padding="var(--ggui-spacing-6)" 
      shadow="md"
      border
    >
      {/* 
        We use Box here to satisfy the requirement for a surfaceVariant background 
        if the Card primitive doesn't directly support the background prop.
        The negative margin is used to fill the Card's padding area.
      */}
      <Box 
        background="var(--ggui-color-surfaceVariant)" 
        margin="-var(--ggui-spacing-6)" 
        padding="var(--ggui-spacing-6)"
        borderRadius="var(--ggui-shape-radius-lg)"
      >
        <div aria-live="polite">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header Section */}
            <Row align="center" gap="var(--ggui-spacing-6)">
              <Heading level={1}>{element.symbol}</Heading>
              <Stack gap="var(--ggui-spacing-1)">
                <Row align="center" gap="var(--ggui-spacing-3)">
                  <Heading level={3}>{element.name}</Heading>
                  <Badge variant="primary">{element.category}</Badge>
                </Row>
              </Stack>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" />

            {/* Data Grid Section */}
            <Row gap="var(--ggui-spacing-12)">
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                  Atomic Number
                </Text>
                <Heading level={4}>{element.atomicNumber}</Heading>
              </Stack>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                  Atomic Weight
                </Text>
                <Text variant="bodyLarge">{element.atomicWeight}</Text>
              </Stack>
            </Row>
          </Stack>
        </div>
      </Box>
    </Card>
  );
}


